// GTM Domain Agent v2 — Platform-Aware Agentic Router
// Upgraded: 2026-03-23 — Full domain catalog, tenant_metadata awareness, NL→action mapping
const input = $input.first().json;
const body = input.body || input;
const goal = body.goal;
const tenant_id = body.tenant_id || $vars.DEFAULT_TENANT_ID || 'kahuna';
const context = body.context || {};

if (!goal) {
  return [{ json: { error: 'Missing required field: goal', tenant_id } }];
}

const N8N_BASE = 'https://mmurawala.app.n8n.cloud';
const N8N_API_KEY = $vars.N8N_API_KEY;
const ANTHROPIC_API_KEY = $vars.ANTHROPIC_API_KEY_N8N;
const GW_MASTER_KEY = $vars.key_master;
const ACTION_MAP_TABLE = 'nTBOiE9byj3KcHVQ';
const GW_PATH = '/webhook/orchestrate-v2';
const MODEL = 'claude-sonnet-4-6';
const MAX_TURNS = 15;

// — Fetch action map for tool validation —
const actionMapResp = await this.helpers.httpRequest({
  method: 'GET',
  url: `${N8N_BASE}/api/v1/data-tables/${ACTION_MAP_TABLE}/rows?limit=250`,
  headers: { 'X-N8N-API-KEY': N8N_API_KEY },
  json: true
});
const actionMap = (actionMapResp.data || actionMapResp.rows || []);
const validActions = new Set(actionMap.map(r => `${r.api_name}.${r.action}`));

// — System Prompt —
const systemPrompt = `You are the Ascend GTM Domain Agent — an AI assistant that executes marketing, sales, analytics, and productivity tasks through the Ascend Gateway platform.

You serve tenant: "${tenant_id}"

## HOW THE PLATFORM WORKS
- You call the ascend_gateway tool with {api_name, action, params}
- The gateway automatically resolves tenant config and injects account IDs (customer_id, property_id, ad_account_id, etc.) from tenant_metadata
- You do NOT need to know or pass internal account IDs — the platform handles this
- For most queries, you just need the api_name, action, and any query-specific params (date ranges, filters, object types)

## CRITICAL RULES
1. NEVER ask the user for account IDs, customer IDs, or property IDs — tenant config provides them automatically
2. ALWAYS use the think tool first to plan multi-step queries
3. When a query spans multiple domains (e.g. "compare ad spend to website traffic"), make parallel gateway calls
4. Summarize data in a human-readable format — tables, bullet points, key metrics — never dump raw JSON
5. If a gateway call returns an error, explain what went wrong and suggest alternatives
6. Default date range is LAST_7_DAYS unless the user specifies otherwise

## AVAILABLE DOMAINS & KEY ACTIONS

### Advertising
- **google_ads**: campaigns, ad_groups, keywords, custom_query (GAQL), mutate
- **meta_ads**: campaigns, ad_sets, insights
- **linkedin_ads**: campaigns, analytics, creatives
- **microsoft_ads**: campaigns, ad_groups, ads, keywords, report, accounts

### Analytics
- **ga4**: report (sessions, users, pageviews), realtime, performance (source/medium), list_streams
- **google_search_console**: query (search analytics), performance, sitemaps
- **google_tag_manager**: list_accounts, list_containers, list_tags, list_triggers

### CRM
- **hubspot**: contacts, companies, deals, search, get, create, update, pipelines, owners, tasks, meetings, tickets, properties, workflows, campaigns
- **salesforce**: query (SOQL), get, create, update, describe, search (SOSL), limits, metadata, delete, upsert, composite
- **apollo**: search, enrich, organization_search, organization_enrich
- **gong**: calls, call_transcript, users, stats

### Marketing / Content
- **wordpress**: posts, get_post, create_post, update_post, delete_post, pages, categories, media
- **semrush**: domain_overview, keyword_overview, backlinks, organic_results

### Productivity
- **google_sheets**: read, write, append, list, clear, create, batch_update
- **google_calendar**: list, create, get, update, delete, free_busy, calendars
- **google_drive**: list, get, search, create, copy, move, delete, download, permissions, export
- **google_docs**: get, create, append
- **google_slides**: get, create, batch_update
- **gmail**: send, list, read, draft, search, labels, reply, trash, threads
- **outlook**: send, list, read, search, calendar_events
- **slack**: send, list_channels, search, read_channel, read_thread, list_users, reactions_add
- **notion**: search, get_page, create_page, update_page, query_database, get_database, get_markdown, update_markdown

### AI
- **anthropic**: messages, batch_create/get/list/cancel/results, count_tokens, models
- **openai**: chat, embeddings, images, audio_transcribe, audio_speech, responses
- **gemini**: generate, image, search, code, research, embed, tts, imagen, veo
- **groq**: chat, audio_transcribe
- **perplexity**: chat
- **deepseek**: chat, fim

### Creative
- **leonardo**: generate, status, models, upscale, image_to_image
- **gamma**: generate (presentations), status, list_themes

### Platform Ops
- **github**: get_file, create_or_update_file, list_contents, list_repos
- **handover**: (internal platform operations)

## COMMON QUERY PATTERNS

| User says | Action |
|-----------|--------|
| "Show me my Google Ads performance" | google_ads.campaigns |
| "How is my website traffic?" | ga4.report {metrics: sessions, users, pageviews} |
| "What keywords are we ranking for?" | google_search_console.query |
| "Show me my Meta ad campaigns" | meta_ads.campaigns |
| "List my HubSpot contacts" | hubspot.contacts |
| "Show Salesforce accounts" | salesforce.query {soql: 'SELECT Id, Name FROM Account LIMIT 10'} |
| "How are LinkedIn ads doing?" | linkedin_ads.analytics |
| "Show me SEMrush data" | semrush.domain_overview |
| "What blog posts do we have?" | wordpress.posts |
| "Show my Gong calls" | gong.calls |
| "Send a Slack message" | slack.send |
| "What is on my calendar?" | google_calendar.list |

## PARAM HINTS
- **ga4.report**: {metrics: [{name:'sessions'},{name:'totalUsers'}], dimensions: [{name:'date'}], dateRanges: [{startDate:'7daysAgo', endDate:'today'}]}
- **google_ads.campaigns**: {date_range: 'LAST_7_DAYS'} — GAQL auto-generated by handler
- **google_ads.custom_query**: {gaql: 'SELECT campaign.name, metrics.clicks FROM campaign WHERE ...'}
- **meta_ads.campaigns**: {fields: 'name,status,objective', limit: 25}
- **meta_ads.insights**: {fields: 'impressions,clicks,spend,ctr', date_preset: 'last_7d', level: 'campaign'}
- **hubspot.search**: {objectType: 'contacts', filters: [{propertyName:'email', operator:'CONTAINS_TOKEN', value:'@example.com'}]}
- **salesforce.query**: {soql: 'SELECT Id, Name FROM Account LIMIT 10'}
- **google_search_console.query**: {startDate: '2026-03-01', endDate: '2026-03-22', dimensions: ['query'], rowLimit: 25}
- **slack.send**: {channel: '#channel-name', text: 'Hello!'}
- **wordpress.posts**: {per_page: 10, status: 'publish'}

Always be concise, action-oriented, and format responses for readability.`;

// — Tools —
const tools = [
  {
    name: 'think',
    description: 'Plan your approach before executing. Use this to reason about which domains and actions to call, what params to use, and how to combine results. ALWAYS use this first for complex or multi-domain queries.',
    input_schema: { type: 'object', properties: { thought: { type: 'string', description: 'Your reasoning and plan' } }, required: ['thought'] }
  },
  {
    name: 'ascend_gateway',
    description: 'Execute a GTM action through the Ascend Gateway. The gateway auto-injects tenant account IDs — you only need api_name, action, and query-specific params.',
    input_schema: {
      type: 'object',
      properties: {
        api_name: { type: 'string', description: 'The API domain (e.g. google_ads, ga4, hubspot, meta_ads)' },
        action: { type: 'string', description: 'The action to execute (e.g. campaigns, report, contacts)' },
        params: { type: 'object', description: 'Action-specific parameters. Account IDs are auto-injected.' }
      },
      required: ['api_name', 'action']
    }
  },
  {
    name: 'list_domain_actions',
    description: 'List all available actions for a specific API domain, or all domains if no filter. Use only if you need to discover actions not in your built-in catalog.',
    input_schema: { type: 'object', properties: { api_name: { type: 'string', description: 'Filter to a specific API domain (optional)' } } }
  }
];

// — Tool Execution —
async function executeTool(name, toolInput) {
  if (name === 'think') return JSON.stringify({ noted: true });

  if (name === 'list_domain_actions') {
    const filtered = toolInput.api_name ? actionMap.filter(r => r.api_name === toolInput.api_name) : actionMap;
    return JSON.stringify(filtered.map(r => ({ api_name: r.api_name, action: r.action, description: r.description || '', body_mode: r.body_mode || '' })));
  }

  if (name === 'ascend_gateway') {
    const apiName = toolInput.api_name;
    const action = toolInput.action;
    const key = `${apiName}.${action}`;
    if (!validActions.has(key)) {
      const apiExists = actionMap.some(r => r.api_name === apiName);
      if (!apiExists) return JSON.stringify({ error: `Unknown API domain: ${apiName}`, hint: 'Use list_domain_actions to discover available domains' });
      const available = actionMap.filter(r => r.api_name === apiName).map(r => r.action);
      return JSON.stringify({ error: `Unknown action: ${action} for ${apiName}`, available_actions: [...new Set(available)] });
    }
    try {
      const gwResp = await this.helpers.httpRequest({
        method: 'POST', url: `${N8N_BASE}${GW_PATH}`,
        headers: { 'Content-Type': 'application/json', 'x-api-key': GW_MASTER_KEY },
        body: { api_name: apiName, action, tenant_id, params: toolInput.params || {} },
        json: true, timeout: 30000
      });
      const respStr = JSON.stringify(gwResp);
      if (respStr.length > 15000) {
        const data = gwResp.data || gwResp.result || gwResp;
        const items = Array.isArray(data) ? data : (data.rows || data.results || data.items || [data]);
        const truncated = items.slice(0, 20);
        return JSON.stringify({ _truncated: true, _total_items: items.length, _showing: truncated.length, data: truncated });
      }
      return respStr;
    } catch (e) {
      const errMsg = e.message || String(e);
      return JSON.stringify({
        error: errMsg, api_name: apiName, action,
        hint: errMsg.includes('401') ? 'Auth error — credential may need re-authorization'
            : errMsg.includes('404') ? 'Endpoint not found — check action name'
            : errMsg.includes('429') ? 'Rate limited — try again in a moment'
            : 'Check params and try again'
      });
    }
  }
  return JSON.stringify({ error: `Unknown tool: ${name}` });
}

// — Agentic Loop —
let messages = [{ role: 'user', content: goal }];
if (context.history && Array.isArray(context.history)) {
  messages = [...context.history, { role: 'user', content: goal }];
}

let finalResponse = '';
let totalTokens = { input: 0, output: 0 };

for (let turn = 0; turn < MAX_TURNS; turn++) {
  const result = await this.helpers.httpRequest({
    method: 'POST', url: 'https://api.anthropic.com/v1/messages',
    headers: { 'Content-Type': 'application/json', 'x-api-key': ANTHROPIC_API_KEY, 'anthropic-version': '2023-06-01' },
    body: { model: MODEL, max_tokens: 4096, system: systemPrompt, tools, messages },
    json: true
  });
  if (result.error) throw new Error(`Anthropic error: ${JSON.stringify(result.error)}`);
  if (result.usage) { totalTokens.input += result.usage.input_tokens || 0; totalTokens.output += result.usage.output_tokens || 0; }
  messages.push({ role: 'assistant', content: result.content });
  if (result.stop_reason === 'end_turn') { finalResponse = result.content.filter(b => b.type === 'text').map(b => b.text).join('\n'); break; }
  const toolUseBlocks = result.content.filter(b => b.type === 'tool_use');
  if (toolUseBlocks.length === 0) { finalResponse = result.content.filter(b => b.type === 'text').map(b => b.text).join('\n'); break; }
  const toolResults = [];
  for (const tu of toolUseBlocks) { const tr = await executeTool.call(this, tu.name, tu.input); toolResults.push({ type: 'tool_result', tool_use_id: tu.id, content: tr }); }
  messages.push({ role: 'user', content: toolResults });
}

return [{ json: { response: finalResponse, tenant_id, goal, turns: Math.floor(messages.length / 2), tokens: totalTokens } }];
